  <script type="module">
    import * as THREE from "three/webgpu";
    import { cameraPosition } from "three/tsl";

    const renderer = new THREE.WebGPURenderer(); // also fails with { forceWebGL: true }
    renderer.setSize(800, 450);
    document.body.appendChild(renderer.domElement);

    const scene = new THREE.Scene();

    // any shader that references the TSL `cameraPosition` node
    const material = new THREE.MeshBasicNodeMaterial();
    material.colorNode = cameraPosition;

    scene.add(new THREE.Mesh(new THREE.BoxGeometry(), material));

    const w = 800, h = 450;

    const camLeft = new THREE.PerspectiveCamera(50, w / 2 / h, 0.1, 10);
    camLeft.position.set(-0.5, 0, 3);
    camLeft.viewport = new THREE.Vector4(0, 0, w / 2, h);
    camLeft.updateMatrixWorld();

    const camRight = new THREE.PerspectiveCamera(50, w / 2 / h, 0.1, 10);
    camRight.position.set(0.5, 0, 3);
    camRight.viewport = new THREE.Vector4(w / 2, 0, w / 2, h);
    camRight.updateMatrixWorld();

    const arrayCamera = new THREE.ArrayCamera([camLeft, camRight]);

    await renderer.init();
    renderer.render(scene, arrayCamera);
    // console: THREE.TSL: TypeError: Cannot destructure property 'camera' of 'undefined' as it is undefined.
  </script>
